<span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">VERSION</span><span style="color:#89DDFF;">()</span><span style="color:#A6ACCD;">;</span></span>
